use anyhow::{anyhow, Result};

fn validate_age(age: i32) -> Result<()> {
    if age < 0 {
        return Err(anyhow!("Age cannot be negative: {}", age));
    }
    if age > 150 {
        return Err(anyhow!("Age seems unrealistic: {}", age));
    }
    Ok(())
}

use anyhow::{Context, Result};

fn process_file(path: &str) -> Result<Vec<u64>> {
    let content = std::fs::read_to_string(path)
        .with_context(|| format!("Could not read file: {}", path))?;

    let numbers: Vec<u64> = content
        .lines()
        .enumerate()
        .map(|(i, line)| {
            line.trim()
                .parse::<u64>()
                .with_context(|| format!("Invalid number on line {}: '{}'", i + 1, line))
        })
        .collect::<Result<_>>()?;

    Ok(numbers)
}

use anyhow::{bail, Result};

fn parse_command(input: &str) -> Result<(&str, &str)> {
    let parts: Vec<&str> = input.splitn(2, ' ').collect();
    if parts.len() != 2 {
        bail!("Expected 'command argument', got: '{}'", input);
    }
    Ok((parts[0], parts[1]))
}

use anyhow::Result;
use std::io;

fn handle_error(result: Result<()>) {
    if let Err(err) = result {
        if let Some(io_err) = err.downcast_ref::<io::Error>() {
            println!("IO error: {}", io_err);
        } else {
            println!("Other error: {}", err);
        }
    }
}
